LAYER
	NAME "lote"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT * FROM geo.v_lote) as kaypacha using unique gid using srid=32718"
	INCLUDE "configuracion/postgresql_kaypacha.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:32718"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Lote || Municipalidad Distrital de Machupicchu - Cusco :: Perú"
		"wfs_title" "Lote"
		"wfs_credit" "Kaypacha"
		"wfs_srs" "EPSG:32718"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		#"gml_nume_doc_type" "Character"
		"gml_idlote_type" "Character"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Lote"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 100 107 99
			WIDTH 1
		END
	END
END # Layer
